function check_payment(card_number, address_type)
{
	var error = "<ul>";
	if(!validPaymentCard(card_number)){
		error += "<li>"+WARNING_PAYMENT_CARD_INVALID+"</li>";
	}
	if(address_type=="new")
	{
		var new_street = $("#payment_address_new_street").val();
		var new_country = $("#payment_address_new_country").val();
		var new_city = $("#payment_address_new_city").val();
		var new_state = $("#payment_address_new_state").val();
		var new_postcode = $("#payment_address_new_postcode").val();
		if(!validEmpty(new_street)){
			error += "<li>"+WARNING_ADDRESS_STREET_EMPTY+"</li>";
		}
		if(!validEmpty(new_country)){
			error += "<li>"+WARNING_ADDRESS_COUNTRY_EMPTY+"</li>";
		}
		if(!validEmpty(new_city)){
			error += "<li>"+WARNING_ADDRESS_CITY_EMPTY+"</li>";
		}
		if(!validEmpty(new_state)){
			error += "<li>"+WARNING_ADDRESS_STATE_EMPTY+"</li>";
		}
		if(!validEmpty(new_postcode)){
			error += "<li>"+WARNING_ADDRESS_POSTCODE_EMPTY+"</li>";
		}
	}
	error += "</ul>";
	return error;
}
function payment_submit()
{
	var address_type = $('input[name=payment_check_address]:checked').val();
	var card_number = $("#payment_card_number").val();
	if ( address_type== "old")
	{
		var address_id = $("input:radio[name ='payment_address']:checked").val();
		$("#form_address_id").val(address_id);
		var error = check_payment(card_number, address_type);
	}else{
		$("#form_address_id").val("");
	var error = check_payment(card_number, address_type);
	}
	if(error=="<ul></ul>")
	{
		$("#error_form_client_payment").html("");
		$(".check-step-button").removeClass("select_confirm");
		$(".check-step-button").removeClass("select_payment");
		$(".check-step-button").addClass("select_site");
		$('#payment_information').addClass("hiden_step");
		$("#confirmation").removeClass("hiden_step");
		$("#step-confir").addClass("title-confir");
		getClientInfomations();
	}else{
		$("#error_form_client_payment").html(error);
	}
}

function contact_submit() {
	var error = "<ul>";
	var lengthEmail = $('#group_email .mfield_value').length;
	var email = $('#group_email .group_home #email_value').val();
	if(lengthEmail!=0 && !validEmpty(email)){
		error += "<li>"+WARNING_EMAIL_EMPTY+"</li>";
		$('#group_email .mfield_value:eq('+i+')').focus();
	}else{
		var flat = 0;
		for(var i=0; i<lengthEmail; i++)
		{
			var email = $('#group_email .mfield_value:eq('+i+') input').val();
			var group = $('#group_email .group_name:eq('+i+')').html();
			if(!validateEmail(email))
			{
				if(i==0)
					error += "<li>"+WARNING_EMAIL_INVALID+"</li>";
				else
					error += "<li>"+lib_translate_var("Invalid Email address of group group_name", {group_name:group})+"'</li>";
				flat++;
				if(flat==1)
					$('#group_email .mfield_value:eq('+i+')').focus();
			}
		}
	}
	//Valid website
	var lengthWeb = $('#group_website .mfield_value').length;
	var flat = 0;
	for(var i=0; i<lengthWeb; i++)
	{
		var protocol = $('#group_website .mfield_value:eq('+i+') select').val();
		var domain = $('#group_website .mfield_value:eq('+i+') input').val();
		var web = protocol+domain
		var group = $('#group_website .group_name:eq('+i+')').html();
		if(i==0 && !validEmpty(web))
		{
			error += "<li>"+WARNING_URL_EMPTY+"</li>";
			$('#group_website .mfield_value:eq('+i+')').focus();
		}
		if(!validURL(web))
		{
			if(i==0)
				error += "<li>"+WARNING_URL_INVALID+"</li>";
			else
				error += "<li>"+lib_translate_var("Invalid Website of group group_name", {group_name:group})+"</li>";
			flat++;
			if(flat==1)
				$('#group_website .mfield_value:eq('+i+')').focus();
		}
	}
	//Valid Phone
	var lengthPhone = $('#group_phone .mfield_value').length;
		var flat = 0;
		for(var i=0; i<lengthPhone; i++)
		{
			var phone = $('#group_phone .mfield_value:eq('+i+') input').val();
			var group = $('#group_phone .group_name:eq('+i+')').html();
			if(!validEmpty(phone))
			{
				if(i==0)
					error += "<li>"+WARNING_PHONE_EMPTY+"</li>";
				else
					error += "<li>"+lib_translate_var("Phone number of group group_name", {group_name:group})+"</li>";
				flat++;
				if(flat==1)
					$('#group_phone .mfield_value:eq('+i+')').focus();
			}
		}
	//Valid address
	var lengthAdd = $('#group_address .mfield_street').length;
	var flat = 0;
	for(var i=0; i<lengthAdd; i++)
	{
		var group = $('#group_address .group_name:eq('+i+')').html();
		var street = $('#group_address .mfield_street:eq('+i+') input').val();
		flat++;
		if(!validEmpty(street))
		{
			if(i==0)
				error += "<li>"+WARNING_ADDRESS_STREET_EMPTY+"</li>";
			else
				error += "<li>"+lib_translate_var("Street group_name can't be blank", {group_name:group})+"</li>";
			if(flat==1)
				$('#group_address .mfield_street:eq('+i+') input').focus();
		}
		var country = $('#group_address .mfield_country:eq('+i+') input').val();
		if(!validEmpty(country))
		{
			if(i==0)
				error += "<li>"+WARNING_ADDRESS_COUNTRY_EMPTY+"</li>";
			else
				error += "<li>"+lib_translate_var("Country group_name can't be blank", {group_name:group})+"</li>";
			if(flat==1)
				$('#group_address .mfield_country:eq('+i+') input').focus();
		}
		var city = $('#group_address .mfield_city:eq('+i+') input').val();
		if(!validEmpty(city))
		{
			if(i==0)
				error += "<li>"+WARNING_ADDRESS_CITY_EMPTY+"</li>";
			else
				error += "<li>"+lib_translate_var("City group_name can't be blank", {group_name:group})+"</li>";
			if(flat==1)
				$('#group_address .mfield_city:eq('+i+') input').focus();
		}
		var state = $('#group_address .mfield_state:eq('+i+') input').val();
		if(!validEmpty(state))
		{
			if(i==0)
				error += "<li>"+WARNING_ADDRESS_STATE_EMPTY+"</li>";
			else
				error += "<li>"+lib_translate_var("State group_name can't be blank", {group_name:group})+"</li>";
			if(flat==1)
				$('#group_address .mfield_state:eq('+i+') input').focus();
		}
		var postcode = $('#group_address .mfield_postcode:eq('+i+') input').val();
		if(!validEmpty(postcode))
		{
			if(i==0)
				error += "<li>"+WARNING_ADDRESS_POSTCODE_EMPTY+"</li>";
			else
				error += "<li>"+lib_translate_var("Portal Code group_name can't be blank", {group_name:group})+"</li>";
			if(flat==1)
				$('#group_address .mfield_postcode:eq('+i+') input').focus();
		}
	}
	//
	error +="</ul>";
	if(error=="<ul></ul>")
	{
		$("#submit_contact_form").val("");
		$( "#submit_contact_form" ).trigger( "click" );
	}else{
		$("#"+ERROR_FORM_CLIENT).html(error);
	}
}

//vienntl : 2016/10/14 - Start
// New Create Client 
// vienntl : 2016/10/14 - End
$(document).on('turbolinks:load', function() {
	//  next step create new client
	$("#btn_step_1").on("click", function(){
		$('.create_client').find('i:first');
		$('#icon_new_client_step_1_done').fadeIn().removeClass('lable_new_client_step_1_done');
		$('.create_client').find('i:nth-child(3)').css("color","#db6410");
		$('#contact_information').addClass("hiden_step");
		$("#payment_information").removeClass("hiden_step");
		$(".contact_info").addClass("text-step");
	});

	// previous step create new client
	$("#btn_pre_step_2").on("click", function(){
		$(".check-step-button").removeClass("select_payment");
		$(".check-step-button").removeClass("select_site");
		$(".check-step-button").addClass("select_contact");
		$('#contact_information').removeClass("hiden_step");
		$("#payment_information").addClass("hiden_step");
	});
	$("#btn_pre_step_3").on("click", function(){
		$(".check-step-button").removeClass("select_confirm");
		$(".check-step-button").removeClass("select_site");
		$(".check-step-button").addClass("select_payment");
		$('#payment_information').removeClass("hiden_step");
		$("#sites_information").addClass("hiden_step");
	});
	$("#btn_pre_step_4").on("click", function(){
		// $(".check-step-button").removeClass("select_confirm");
		// $(".check-step-button").removeClass("select_payment");
		// $(".check-step-button").addClass("select_site");
		// $('#sites_information').removeClass("hiden_step");
		// $("#confirmation").addClass("hiden_step");
		$('#payment_information').removeClass("hiden_step");
		$("#confirmation").addClass("hiden_step");
		$("#step-confir").removeClass("title-confir");
	});
});
function showHideDiv(id_show, id_hide)
{
	$("#"+id_show).show("slow");
	$("#"+id_hide).hide("slow");
}
function showDiv(id_div)
{
	$("#"+id_div).show("slow");
}
function hideDiv(id_div)
{
	$("#"+id_div).hide("slow");
}
function checkBoxField(group)
{
    if(group=="org")
    {
      var field = $('#hidden_group_org .group-field').clone();
      $(field).appendTo('#group_organisation .group_home');
      showDiv('wrap_org');
      showDiv('wrap_org_edit');
    }
    if(group=="web")
    {
      var field = $('#hidden_group_web .group-field').clone();
      $(field).appendTo('#group_website .group_home');
      showDiv('wrap_web');
      showDiv('wrap_web_edit');
    }
    if(group=="phone")
    {
      var field = $('#hidden_group_phone .group-field').clone();
      $(field).appendTo('#group_phone .group_home');
      showDiv('wrap_phone');
      showDiv('wrap_phone_edit');
    }
    $(".popup_add_field").hide();
}
