$(document).ajaxError(function(event,xhr,options,exc) {
    var errors = JSON.parse(xhr.responseText);
    var er ="<ul>";
    var err_divid = errors[0]
    for(var i = 1; i < errors.length; i++){
        var list = errors[i];
        er += "<li>"+list+"</li>"
    }
    er+="</ul>"
    $("#"+err_divid).html(er);
});

